#include<cstdio>
#include<cstring>
#include<algorithm>
#define rep(a,b,c) for(int c=(a);c<=(b);++c)
inline int read()
{
	int res=0;char ch=getchar();bool flag=0;while(ch<'0'||ch>'9')flag^=(ch=='-'),ch=getchar();
	while(ch<='9'&&ch>='0')res=res*10+(ch^48),ch=getchar();return flag ? -res : res ;
}
template<typename T> inline T max(const T&x,const T&y){return x<y?y:x;}
template<typename T> inline T min(const T&x,const T&y){return x<y?x:y;}
const int N=5e4+10,BK=512;struct Back{int p,l,r,a;inline Back(const int &x=0,const int &y=0,const int &z=0,const int &c=0){p=x;l=y;r=z;a=c;}}stk[N];
int a[N],loc[N],P[N],pp,n,Q,blk,ans[N],ql[N],qr[N],B[N],top,Ans,tmp[N];
struct Sort{int l,r,idx;inline bool operator<(const Sort &Q)const{return loc[l]==loc[Q.l]?r<Q.r:l<Q.l;}}t[N];
inline int fnd(const int &k){int l(1),r(pp),mid,t(1);while(l<=r)P[mid=(l+r)>>1]<=k?l=mid+1,t=mid:r=mid-1;return t;}
inline void Init(){rep(1,n,i)loc[i]=(i-1)/BK+1;blk=n/BK+1;rep(1,blk,i)B[i]=(i-1)*BK+1;}
inline int BruteForce(const int &l,const int &r){int res=0;rep(l,r,i){if(!tmp[a[i]])tmp[a[i]]=i;else res=max(res,i-tmp[a[i]]);} rep(l,r,i)tmp[a[i]]=0;return res;}
inline void ins(const int &x)
{
	stk[++top]=Back(a[x],ql[a[x]],qr[a[x]],Ans);if(!ql[a[x]])ql[a[x]]=qr[a[x]]=x;
	ql[a[x]]=min(ql[a[x]],x);qr[a[x]]=max(qr[a[x]],x);Ans=max(Ans,qr[a[x]]-ql[a[x]]);stk[top].a=Ans;
}
inline void BackTo(const int &x){while(top>x){Ans=stk[top].a;ql[stk[top].p]=stk[top].l;qr[stk[top].p]=stk[top].r;--top;}}
int main()
{
	n=read()+1;Q=read();rep(2,n,i)P[i]=a[i]=a[i-1]+read();Init();
	std::sort(P+1,P+n+1);pp=std::unique(P+1,P+n+1)-P-1;rep(1,n,i)a[i]=fnd(a[i]);
	rep(1,Q,i)t[i].l=read(),t[i].r=read()+1,t[i].idx=i;std::sort(t+1,t+Q+1);
	int cur=0,L=1,R=0;rep(1,Q,i)
	{
		if(loc[t[i].l]==loc[t[i].r]){ans[t[i].idx]=BruteForce(t[i].l,t[i].r);continue;}
		if(B[cur]<=t[i].l){while(B[cur]<=t[i].l)++cur;L=B[cur];R=B[cur]-1;memset(ql,0,sizeof(ql));memset(qr,0,sizeof(qr));Ans=top=0;}
		while(R<t[i].r)ins(++R); int tmp=top; while(L>t[i].l)ins(--L);
		ans[t[i].idx]=Ans;BackTo(tmp);L=B[cur];
	}
	rep(1,Q,i)printf("%d\n",ans[i]);return 0;
}
